async function s(e){const n=e.apiKey.trim();if(!n)throw new Error("OpenRouter API key is missing. Add it in AI Models or Settings.");const t=await fetch("https://openrouter.ai/api/v1/chat/completions",{method:"POST",headers:{Authorization:`Bearer ${n}`,"Content-Type":"application/json","HTTP-Referer":"https://github.com/surelle-ha/vindicta","X-Title":"Vindicta"},body:JSON.stringify({model:e.model||"openai/gpt-4.1-mini",messages:e.messages,temperature:.4})});if(!t.ok){const r=await t.text().catch(()=>"");throw new Error(r||`OpenRouter returned HTTP ${t.status}`)}const a=(await t.json())?.choices?.[0]?.message?.content;if(typeof a!="string"||!a.trim())throw new Error("OpenRouter returned an empty response.");return a}async function i(e){const n=(e.url||"http://localhost:11434").replace(/\/$/,""),t=await fetch(`${n}/v1/chat/completions`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({model:e.model||"llama3.2",messages:e.messages,temperature:.4})});if(!t.ok){const r=await t.text().catch(()=>"");throw new Error(r||`Ollama returned HTTP ${t.status}. Is Ollama running at ${n}?`)}const a=(await t.json())?.choices?.[0]?.message?.content;if(typeof a!="string"||!a.trim())throw new Error("Ollama returned an empty response.");return a}export{i as a,s as r};
